using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    private void Start()
    {
        // Initialize player stats
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health <= 0)
        {
            Die();
        }
    }

    private void Die()
    {
        // Handle player death
    }

    public bool PurchaseItem(int itemCost)
    {
        if (currency >= itemCost)
        {
            currency -= itemCost;
            return true;
        }
        return false;
    }

    public int CalculateDamage(int baseDamage, float damageMultiplier)
    {
        return Mathf.FloorToInt(baseDamage * damageMultiplier);
    }
